SELECT
    id, line_no, scene_no, divide_name, divide_no, access_strategy_no, risk_strategy_no, priority, version, deploy_at, is_valid, create_at
FROM divide


        line_no = #{param.lineNo}


        AND divide_name like CONCAT(#{param.divideName}, '%')


        AND divide_no = #{param.divideNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

ORDER BY create_at DESC
LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM divide


        line_no = #{param.lineNo}


        AND divide_name like CONCAT(#{param.divideName}, '%')


        AND divide_no = #{param.divideNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

